framework_css:
@import url("https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Source+Sans+3:wght@300;400;500;600;700&family=Source+Code+Pro:wght@400;600&display=swap");

:root {
  /* Color system (from design + provided palette) */
  --color-primary-900: #111111; /* main text, logo */
  --color-primary-600: #777777; /* secondary text, nav idle */
  --color-secondary-400: #bbbbbb; /* subtle accents */
  --color-secondary-50: #f5f5f5; /* soft background blocks */
  --color-accent-ink: #000000; /* high-contrast accents */

  --color-neutral-0: #ffffff;
  --color-neutral-75: #f7f7f7;
  --color-neutral-100: #f5f5f5;
  --color-neutral-200: #eeeeee; /* hairline rules */
  --color-neutral-300: #cccccc; /* input borders */

  --color-border-subtle: #eeeeee; /* header/footer rules, card separators */
  --color-border-strong: #cccccc;

  --color-success: #4caf50;
  --color-error: #e53935;
  --color-warning: #ffc107;
  --color-info: #2196f3;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 18px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (based on ~8px unit) */
  --space-xxs: 4px;
  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-xxl: 64px;

  --header-height: 72px;
  --container-max-width: 1120px;
}

/* Global reset-ish base */
* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-primary-900);
  background-color: var(--color-neutral-0);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

.container {
  max-width: var(--container-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-md);
  padding-right: var(--space-md);
}

.site-main {
  padding-top: var(--space-xl);
  padding-bottom: var(--space-xxl);
}

/* Header */
.site-header {
  border-bottom: 1px solid var(--color-border-subtle);
  background-color: var(--color-neutral-0);
}

.header-inner {
  display: grid;
  grid-template-columns: auto 1fr;
  align-items: stretch;
}

.site-logo {
  display: inline-flex;
  align-items: center;
  padding-top: var(--space-md);
  padding-bottom: var(--space-md);
  padding-right: var(--space-lg);
  font-family: var(--font-heading);
  font-size: 24px;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-accent-ink);
  border-right: 1px solid var(--color-border-subtle);
}

.logo-word {
  line-height: 1;
}

.logo-bold {
  font-weight: var(--font-weight-bold);
}

.logo-light {
  font-weight: var(--font-weight-light);
}

.logo-dot {
  font-weight: var(--font-weight-bold);
  margin-left: 2px;
}

.primary-nav {
  display: flex;
  justify-content: flex-end;
}

.nav-list {
  display: flex;
  flex: 1;
  align-items: stretch;
  justify-content: flex-end;
  margin: 0;
  padding: 0;
  list-style: none;
}

.nav-item {
  border-left: 1px solid var(--color-border-subtle);
  flex: 0 0 auto;
}

.nav-link {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-md) var(--space-md);
  min-height: var(--header-height);
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-medium);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-primary-600);
  white-space: nowrap;
}

.nav-link:hover,
.nav-link:focus {
  background-color: var(--color-secondary-50);
  color: var(--color-primary-900);
  text-decoration: none;
}

.nav-item-accent .nav-link {
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary-900);
}

.nav-item-accent .nav-link:hover,
.nav-item-accent .nav-link:focus {
  background-color: var(--color-neutral-0);
  text-decoration: underline;
}

/* Utility horizontal rule / dividers for content sections */
.hr,
.section-divider {
  border: 0;
  border-top: 1px solid var(--color-border-subtle);
  margin-top: var(--space-lg);
  margin-bottom: var(--space-lg);
}

/* Footer */
.site-footer {
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-neutral-0);
  padding-top: var(--space-lg);
  padding-bottom: var(--space-xl);
}

.footer-inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
}

.footer-branding {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: var(--space-xs);
}

.footer-logo {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.footer-tagline {
  font-size: var(--font-size-small);
  color: var(--color-primary-600);
}

.footer-nav {
  border-top: 1px solid var(--color-border-subtle);
  border-bottom: 1px solid var(--color-border-subtle);
  padding-top: var(--space-sm);
  padding-bottom: var(--space-sm);
}

.footer-nav-list {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-xs) var(--space-lg);
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-nav-item {
  position: relative;
}

.footer-nav-item + .footer-nav-item::before {
  content: "";
  position: absolute;
  left: -12px;
  top: 50%;
  width: 1px;
  height: 10px;
  background-color: var(--color-border-subtle);
  transform: translateY(-50%);
}

.footer-nav-link {
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-primary-600);
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-primary-900);
  text-decoration: none;
}

.footer-meta {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-xs);
}

.footer-copy {
  font-size: var(--font-size-small);
  color: var(--color-primary-600);
  margin: 0;
}

.footer-year {
  white-space: nowrap;
}

/* Headings helpers for content area (editorial look) */

h1,
h2,
h3,
h4 {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-sm);
}

small,
.text-small {
  font-size: var(--font-size-small);
}

/* Form baseline (matching minimal aesthetic, for future use) */

form {
  max-width: 640px;
}

.form-group {
  margin-bottom: var(--space-md);
}

.form-label {
  display: block;
  margin-bottom: var(--space-xxs);
  font-size: var(--font-size-small);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--color-primary-600);
}

input[type="text"],
input[type="email"],
input[type="password"],
input[type="number"],
textarea,
select {
  width: 100%;
  padding: 8px 10px;
  border: 1px solid var(--color-neutral-300);
  border-radius: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  color: var(--color-primary-900);
  background-color: var(--color-neutral-0);
}

input:focus,
textarea:focus,
select:focus {
  outline: none;
  border-color: var(--color-primary-900);
}

.form-help {
  margin-top: var(--space-xxs);
  font-size: var(--font-size-small);
  color: var(--color-primary-600);
}

.form-error {
  margin-top: var(--space-xxs);
  font-size: var(--font-size-small);
  color: var(--color-error);
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .header-inner {
    grid-template-columns: 1fr;
  }

  .site-logo {
    border-right: none;
    border-bottom: 1px solid var(--color-border-subtle);
    padding-right: 0;
  }

  .primary-nav {
    overflow-x: auto;
  }

  .nav-list {
    justify-content: flex-start;
  }
}

@media (max-width: 640px) {
  .site-main {
    padding-top: var(--space-lg);
    padding-bottom: var(--space-xl);
  }

  .footer-nav-item + .footer-nav-item::before {
    display: none;
  }

  .footer-nav-list {
    gap: var(--space-xs) var(--space-md);
  }
}
